#include <iostream>
#include <stdexcept>

void save_document() {
    try {
        // some operation that might throw
        throw std::runtime_error("File not found");
    }
    catch (const std::exception& e) {
        // Noncompliant: only rethrowing
        throw;
    }
}

compliant:
#include <iostream>
#include <stdexcept>

void save_document() {
    try {
        // some operation that might throw
        throw std::runtime_error("File not found");
    }
    catch (const std::exception& e) {
        // Compliant: doing logging before rethrowing
        std::cerr << "Error occurred: " << e.what() << std::endl;
        throw;
    }
}

// Or even better, just let it propagate naturally:
void save_document_better() {
    // Let exceptions propagate naturally
    // some operation that might throw
    throw std::runtime_error("File not found");
}
